class Solution:
    def orangesRotting(self, grid):
        m = len(grid)
        n = len(grid[0])
        g = [row[:] for row in grid]
        def fresh_count():
            return sum(1 for i in range(m) for j in range(n) if g[i][j] == 1)
        if fresh_count() == 0:
            return 0
        minutes = 0
        while True:
            to_rot = []
            for i in range(m):
                for j in range(n):
                    if g[i][j] == 2:
                        for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                            ni, nj = i + di, j + dj
                            if 0 <= ni < m and 0 <= nj < n and g[ni][nj] == 1:
                                to_rot.append((ni, nj))
            if not to_rot:
                break
            for i, j in to_rot:
                g[i][j] = 2
            minutes += 1
        return -1 if fresh_count() > 0 else minutes

