class Solution:
    def orangesRotting(self, grid):
        from collections import deque
        m = len(grid)
        n = len(grid[0])
        q = deque()
        fresh = 0
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 2:
                    q.append((i, j))
                elif grid[i][j] == 1:
                    fresh += 1
        if fresh == 0:
            return 0
        minutes = 0
        rotten = [row[:] for row in grid]
        while q:
            minutes += 1
            for _ in range(len(q)):
                i, j = q.popleft()
                for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    ni, nj = i + di, j + dj
                    if 0 <= ni < m and 0 <= nj < n and rotten[ni][nj] == 1:
                        rotten[ni][nj] = 2
                        fresh -= 1
                        q.append((ni, nj))
        return -1 if fresh > 0 else minutes - 1

