var orangesRotting = function(grid) {
    const m = grid.length, n = grid[0].length;
    let q = [];
    let fresh = 0;
    const rotten = grid.map(row => row.slice());
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (rotten[i][j] === 2) q.push([i, j]);
            else if (rotten[i][j] === 1) fresh++;
        }
    }
    if (fresh === 0) return 0;
    let minutes = 0;
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    while (q.length > 0) {
        minutes++;
        const next = [];
        for (const [i, j] of q) {
            for (const [di, dj] of dirs) {
                const ni = i + di, nj = j + dj;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n && rotten[ni][nj] === 1) {
                    rotten[ni][nj] = 2;
                    fresh--;
                    next.push([ni, nj]);
                }
            }
        }
        q = next;
    }
    return fresh > 0 ? -1 : minutes - 1;
};
